        {"title": "编写条件查询", "description": "编写SQL查询users表中年龄大于18岁的用户。", "instructions": "请编写SQL语句", "exercise_type": "code", "difficulty": "easy", "category": "SQL查询", "knowledge_point": "WHERE条件", "code_template": "-- 查询年龄>18的用户\n", "solution": "SELECT * FROM users WHERE age > 18;", "hint": "使用WHERE子句过滤"},
        {"title": "编写模糊查询", "description": "编写SQL查询users表中邮箱包含@example.com的用户。", "instructions": "请编写SQL语句", "exercise_type": "code", "difficulty": "easy", "category": "SQL查询", "knowledge_point": "LIKE模糊查询", "code_template": "-- 模糊查询邮箱\n", "solution": "SELECT * FROM users WHERE email LIKE '%@example.com%';", "hint": "使用LIKE和通配符%"},
        {"title": "编写排序查询", "description": "编写SQL查询users表所有用户，按创建时间降序排列。", "instructions": "请编写SQL语句", "exercise_type": "code", "difficulty": "easy", "category": "SQL查询", "knowledge_point": "ORDER BY", "code_template": "-- 按创建时间降序\n", "solution": "SELECT * FROM users ORDER BY created_at DESC;", "hint": "使用ORDER BY ... DESC"},
        {"title": "编写分页查询", "description": "编写SQL查询users表第2页数据，每页10条。", "instructions": "请编写SQL语句", "exercise_type": "code", "difficulty": "medium", "category": "SQL查询", "knowledge_point": "LIMIT分页", "code_template": "-- 第2页，每页10条\n", "solution": "SELECT * FROM users LIMIT 10 OFFSET 10;", "hint": "使用LIMIT和OFFSET"},
        {"title": "编写聚合查询", "description": "编写SQL统计users表中用户总数。", "instructions": "请编写SQL语句", "exercise_type": "code", "difficulty": "easy", "category": "SQL查询", "knowledge_point": "COUNT聚合", "code_template": "-- 统计用户总数\n", "solution": "SELECT COUNT(*) AS total_users FROM users;", "hint": "使用COUNT(*)"},
        {"title": "编写分组统计", "description": "编写SQL按城市统计users表中每个城市的用户数量。", "instructions": "请编写SQL语句", "exercise_type": "code", "difficulty": "medium", "category": "SQL查询", "knowledge_point": "GROUP BY", "code_template": "-- 按城市统计用户数\n", "solution": "SELECT city, COUNT(*) AS user_count FROM users GROUP BY city;", "hint": "使用GROUP BY分组"},
        {"title": "编写JOIN查询", "description": "编写SQL查询用户及其订单信息（users和orders表）。", "instructions": "请编写SQL语句", "exercise_type": "code", "difficulty": "medium", "category": "SQL连接", "knowledge_point": "INNER JOIN", "code_template": "-- 查询用户和订单\n", "solution": "SELECT u.*, o.* FROM users u INNER JOIN orders o ON u.id = o.user_id;", "hint": "使用INNER JOIN连接两表"},
        {"title": "编写LEFT JOIN查询", "description": "编写SQL查询所有用户及其订单数量，包括没有订单的用户。", "instructions": "请编写SQL语句", "exercise_type": "code", "difficulty": "medium", "category": "SQL连接", "knowledge_point": "LEFT JOIN", "code_template": "-- 查询所有用户订单数\n", "solution": "SELECT u.id, u.name, COUNT(o.id) AS order_count FROM users u LEFT JOIN orders o ON u.id = o.user_id GROUP BY u.id, u.name;", "hint": "使用LEFT JOIN保留左表所有数据"},
        {"title": "编写子查询", "description": "编写SQL查询有订单的用户信息。", "instructions": "请编写SQL语句", "exercise_type": "code", "difficulty": "medium", "category": "SQL查询", "knowledge_point": "子查询", "code_template": "-- 查询有订单的用户\n", "solution": "SELECT * FROM users WHERE id IN (SELECT DISTINCT user_id FROM orders);", "hint": "使用IN子查询"},
        {"title": "编写INSERT语句", "description": "编写SQL向users表插入一条新用户记录。", "instructions": "请编写SQL语句", "exercise_type": "code", "difficulty": "easy", "category": "DML", "knowledge_point": "INSERT", "code_template": "-- 插入新用户\n", "solution": "INSERT INTO users (username, email, created_at) VALUES ('newuser', 'new@example.com', NOW());", "hint": "使用INSERT INTO ... VALUES"},
        {"title": "编写UPDATE语句", "description": "编写SQL将users表中id=1的用户邮箱更新。", "instructions": "请编写SQL语句", "exercise_type": "code", "difficulty": "easy", "category": "DML", "knowledge_point": "UPDATE", "code_template": "-- 更新用户邮箱\n", "solution": "UPDATE users SET email = 'updated@example.com' WHERE id = 1;", "hint": "使用UPDATE ... SET ... WHERE"},
        {"title": "编写DELETE语句", "description": "编写SQL删除users表中id=1的用户。", "instructions": "请编写SQL语句", "exercise_type": "code", "difficulty": "easy", "category": "DML", "knowledge_point": "DELETE", "code_template": "-- 删除用户\n", "solution": "DELETE FROM users WHERE id = 1;", "hint": "使用DELETE FROM ... WHERE"},
        {"title": "编写建表语句", "description": "编写SQL创建一个products表，包含id, name, price, stock字段。", "instructions": "请编写SQL语句", "exercise_type": "code", "difficulty": "medium", "category": "DDL", "knowledge_point": "CREATE TABLE", "code_template": "-- 创建products表\n", "solution": "CREATE TABLE products (id INT PRIMARY KEY AUTO_INCREMENT, name VARCHAR(100) NOT NULL, price DECIMAL(10,2) NOT NULL, stock INT DEFAULT 0);", "hint": "使用CREATE TABLE定义字段和约束"},
        {"title": "编写ALTER TABLE语句", "description": "编写SQL为products表添加description字段。", "instructions": "请编写SQL语句", "exercise_type": "code", "difficulty": "medium", "category": "DDL", "knowledge_point": "ALTER TABLE", "code_template": "-- 添加字段\n", "solution": "ALTER TABLE products ADD COLUMN description TEXT;", "hint": "使用ALTER TABLE ADD COLUMN"},
        {"title": "编写创建索引语句", "description": "编写SQL为products表的name字段创建索引。", "instructions": "请编写SQL语句", "exercise_type": "code", "difficulty": "medium", "category": "索引", "knowledge_point": "CREATE INDEX", "code_template": "-- 创建索引\n", "solution": "CREATE INDEX idx_product_name ON products(name);", "hint": "使用CREATE INDEX"},
        {"title": "编写创建视图语句", "description": "编写SQL创建一个视图，显示价格大于100的产品。", "instructions": "请编写SQL语句", "exercise_type": "code", "difficulty": "medium", "category": "视图", "knowledge_point": "CREATE VIEW", "code_template": "-- 创建视图\n", "solution": "CREATE VIEW expensive_products AS SELECT * FROM products WHERE price > 100;", "hint": "使用CREATE VIEW AS SELECT"},
        {"title": "编写CASE语句", "description": "编写SQL查询products表，根据价格范围显示等级。", "instructions": "请编写SQL语句", "exercise_type": "code", "difficulty": "medium", "category": "SQL函数", "knowledge_point": "CASE", "code_template": "-- 价格等级\n", "solution": "SELECT name, price, CASE WHEN price < 50 THEN 'low' WHEN price < 100 THEN 'medium' ELSE 'high' END AS level FROM products;", "hint": "使用CASE WHEN ... THEN ... END"},
        {"title": "编写UNION查询", "description": "编写SQL合并两个查询结果（活跃用户和VIP用户）。", "instructions": "请编写SQL语句", "exercise_type": "code", "difficulty": "hard", "category": "SQL查询", "knowledge_point": "UNION", "code_template": "-- 合并查询\n", "solution": "SELECT id, name, 'active' AS type FROM users WHERE status = 'active' UNION SELECT id, name, 'vip' FROM users WHERE is_vip = 1;", "hint": "使用UNION合并两个SELECT"},
        {"title": "编写窗口函数", "description": "编写SQL为products表按价格排名。", "instructions": "请编写SQL语句", "exercise_type": "code", "difficulty": "hard", "category": "SQL函数", "knowledge_point": "窗口函数", "code_template": "-- 价格排名\n", "solution": "SELECT name, price, ROW_NUMBER() OVER (ORDER BY price DESC) AS rank FROM products;", "hint": "使用ROW_NUMBER() OVER(ORDER BY)"},
